Implement a UI for administrators to manually trigger benchmarks on specific workers, with progress tracking and result display.

## Background and Justification
While benchmarks run automatically on schedule, admins may need to:
- Re-benchmark after hardware changes
- Verify performance after troubleshooting
- Compare before/after for optimization work
- Run benchmark on newly added worker immediately

## Implementation Details

### Trigger Button Component
```tsx
interface BenchmarkTriggerButtonProps {
  workerId: string;
  lastBenchmarked: Date | null;
  isRunning: boolean;
  onTrigger: () => void;
  requireAdmin?: boolean;
}

const BenchmarkTriggerButton: React.FC<BenchmarkTriggerButtonProps> = ({
  workerId,
  lastBenchmarked,
  isRunning,
  onTrigger,
  requireAdmin = true,
}) => {
  const { isAdmin } = useAuth();

  if (requireAdmin && !isAdmin) {
    return null;  // Don't show to non-admins
  }

  const canTrigger = !isRunning && (
    !lastBenchmarked || 
    differenceInMinutes(new Date(), lastBenchmarked) > 5
  );

  return (
    <Button 
      onClick={onTrigger}
      disabled={!canTrigger}
      loading={isRunning}
      title={isRunning ? 'Benchmark in progress' : 'Run benchmark now'}
    >
      {isRunning ? 'Running...' : 'Re-benchmark'}
    </Button>
  );
};
```

### Benchmark Progress Modal
```tsx
interface BenchmarkProgressModalProps {
  workerId: string;
  isOpen: boolean;
  onClose: () => void;
}

const BenchmarkProgressModal: React.FC<BenchmarkProgressModalProps> = ({
  workerId,
  isOpen,
  onClose,
}) => {
  const { status, progress, result } = useBenchmarkProgress(workerId);

  return (
    <Modal isOpen={isOpen} onClose={onClose}>
      <ModalHeader>
        <h2>Benchmarking {workerId}</h2>
      </ModalHeader>

      <ModalBody>
        <BenchmarkPhases>
          <Phase name="CPU" status={getPhaseStatus('cpu', progress)} />
          <Phase name="Memory" status={getPhaseStatus('memory', progress)} />
          <Phase name="Disk" status={getPhaseStatus('disk', progress)} />
          <Phase name="Network" status={getPhaseStatus('network', progress)} />
          <Phase name="Compilation" status={getPhaseStatus('compilation', progress)} />
        </BenchmarkPhases>

        <ProgressBar value={progress.overall_pct} />

        {status === 'completed' && result && (
          <ResultSummary>
            <ScoreChange 
              previous={result.previous_score}
              current={result.new_score}
            />
          </ResultSummary>
        )}

        {status === 'failed' && (
          <ErrorDisplay error={progress.error} />
        )}
      </ModalBody>

      <ModalFooter>
        {status === 'running' && (
          <Button variant="secondary" onClick={cancelBenchmark}>
            Cancel
          </Button>
        )}
        <Button onClick={onClose}>
          {status === 'completed' ? 'Done' : 'Close'}
        </Button>
      </ModalFooter>
    </Modal>
  );
};
```

