### WebSocket Integration
```tsx
const useBenchmarkProgress = (workerId: string) => {
  const [status, setStatus] = useState<'idle' | 'running' | 'completed' | 'failed'>('idle');
  const [progress, setProgress] = useState<BenchmarkProgress>({});

  useWebSocket('benchmark_progress', (event) => {
    if (event.data.worker_id === workerId) {
      setProgress(event.data);
    }
  });

  useWebSocket('benchmark_completed', (event) => {
    if (event.data.worker_id === workerId) {
      setStatus('completed');
    }
  });

  return { status, progress };
};
```

