 {"id":"remote_compilation_helper-cdw","title":"Task: Memory Benchmark Implementation (Rust-Native)","description":"## Overview
Implement a pure-Rust memory benchmark measuring bandwidth and latency characteristics relevant to compilation workloads.

## Background and Justification
Memory subsystem performance significantly impacts rustc:
- Large projects allocate gigabytes during compilation
- Incremental compilation benefits from fast cache access
- Workers with slow memory should be scored lower

## Implementation Details

### Benchmark Design
1. **Sequential bandwidth**: Measures raw memory throughput
2. **Random access latency**: Measures cache/memory hierarchy efficiency  
3. **Allocation stress**: Measures allocator performance under load

### Memory Benchmark Implementation
```rust
use std::time::Instant;
use std::alloc::{alloc, dealloc, Layout};

pub struct MemoryBenchmarkResult {
    pub score: f64,
    pub seq_bandwidth_gbps: f64,      // Sequential read/write bandwidth
    pub random_latency_ns: f64,        // Random access latency
    pub alloc_ops_per_second: f64,     // Allocation throughput
}

/// Sequential bandwidth: read/write large contiguous buffer
fn sequential_bandwidth_benchmark() -> f64 {
    const SIZE: usize = 256 * 1024 * 1024;  // 256 MB
    let mut buffer = vec![0u8; SIZE];

    let start = Instant::now();

    // Write pass
    for chunk in buffer.chunks_mut(4096) {
        for byte in chunk.iter_mut() {
            *byte = 0xAA;
        }
    }

    // Read pass with dependency chain
    let mut sum = 0u64;
    for chunk in buffer.chunks(4096) {
        for byte in chunk.iter() {
            sum = sum.wrapping_add(*byte as u64);
        }
    }

    let duration = start.elapsed();
    let bytes_processed = (SIZE * 2) as f64;  // Read + write
    let gbps = bytes_processed / duration.as_secs_f64() / 1e9;

    std::hint::black_box(sum);  // Prevent optimization
    gbps
}

/// Random access latency: pointer chasing through shuffled array
fn random_access_latency_benchmark() -> f64 {
    const SIZE: usize = 64 * 1024 * 1024 / 8;  // 64MB of u64s
    let mut buffer: Vec<usize> = (0..SIZE).collect();

    // Fisher-Yates shuffle for random access pattern
    let mut rng_state = 12345u64;
    for i in (1..SIZE).rev() {
        rng_state = rng_state.wrapping_mul(6364136223846793005).wrapping_add(1);
        let j = (rng_state as usize) % (i + 1);
        buffer.swap(i, j);
    }

    // Create pointer chase
    let mut chase = vec![0usize; SIZE];
    for i in 0..SIZE-1 {
        chase[buffer[i]] = buffer[i + 1];
    }
    chase[buffer[SIZE-1]] = buffer[0];

    // Measure chase time
    let iterations = 10_000_000;
    let start = Instant::now();
    let mut idx = 0usize;
    for _ in 0..iterations {
        idx = chase[idx];
    }
    let duration = start.elapsed();

    std::hint::black_box(idx);
    duration.as_nanos() as f64 / iterations as f64
}

/// Allocation stress: many small allocations
fn allocation_benchmark() -> f64 {
    const ITERATIONS: usize = 100_000;
    const SIZES: [usize; 5] = [64, 256, 1024, 4096, 16384];

    let start = Instant::now();

    for i in 0..ITERATIONS {
        let size = SIZES[i % SIZES.len()];
        let layout = Layout::from_size_align(size, 8).unwrap();
        unsafe {
            let ptr = alloc(layout);
            std::ptr::write_volatile(ptr, 0xAA);
            dealloc(ptr, layout);
        }
    }

    let duration = start.elapsed();
    ITERATIONS as f64 / duration.as_secs_f64()
}

/// Combined benchmark
pub fn run_memory_benchmark() -> MemoryBenchmarkResult {
    let seq_bandwidth = sequential_bandwidth_benchmark();
    let random_latency = random_access_latency_benchmark();
    let alloc_ops = allocation_benchmark();

    // Weighted score (bandwidth most important for compilation)
    let score = (seq_bandwidth * 100.0) + 
                (1000.0 / random_latency) * 50.0 + 
                (alloc_ops / 10000.0) * 20.0;

    MemoryBenchmarkResult {
        score,
        seq_bandwidth_gbps: seq_bandwidth,
        random_latency_ns: random_latency,
        alloc_ops_per_second: alloc_ops,
    }
}
```

